import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { AddSystemService } from 'src/app/shared/services/add-system.service';
import { RoleService } from 'src/app/shared/services/role.service';
import { RuleService } from 'src/app/shared/services/rule.service';
import { ToastService } from 'src/app/shared/services/toast.service';

@Component({
  selector: 'npr-rule-list',
  templateUrl: './rule-list.component.html',
  styleUrls: ['./rule-list.component.scss']
})
export class RuleListComponent implements OnInit {
  rulesData: any = [];
  dtTrigger: any = new Subject();
  dtOptions: DataTables.Settings = {};
  isLoading:boolean = false;
  roleCodes = new permissionsLabels();

  constructor(private ruleService: RuleService,private roleService:RoleService,
              private toastService: ToastService,
              private router:Router,
              private addSystem:AddSystemService,
              private cdr:ChangeDetectorRef) { }

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [5] } ],
      order: [[5, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],

    };
    this.fetchRules();
    this.roleService.fetchScreenPermissions('Create Rule');
    this.roleService.screenLabelList.subscribe(message => this.roleCodes = message);
    console.log(this.roleCodes);
  }

  fetchRules() {
    this.isLoading = true;
    this.ruleService.fetchingRules()
      .subscribe((resp: any) => {
        console.log(resp);
        // this.toastService.successMessage('Data Fetched Successfully!.', '');
        this.rulesData = resp;
        this.isLoading = false;
        this.cdr.markForCheck();
        
        this.dtTrigger.next();
      }, (err: any) => {
        console.error("Error!");
        // this.toastService.errorMessage('Failed to Fetch Data!.', '');
      })
  }

  editRule(row) {
    console.log(row);
    this.router.navigate(["/createrule/edit", row.ruleId])
  }

  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger.unsubscribe();
  }

}
